localStorage.setItem('gl-astra-project', JSON.stringify({"files": {"/pom.xml": "<project xmlns=\"http://maven.apache.org/POM/4.0.0\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"\n\txsi:schemaLocation=\"http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd\">\n\t<modelVersion>4.0.0</modelVersion>\n\t\n\t<groupId>comp40040</groupId>\n\t<artifactId>project</artifactId>\n\t<version>1.0.0</version>\n\n\t<parent>\n\t\t<groupId>com.astralanguage</groupId>\n\t\t<artifactId>astra-cartago-base</artifactId>\n\t\t<version>2.0.12</version>\n\t\t<relativePath/>\n\t</parent>\n\n\t<properties>\n\t\t<maven.compiler.source>17</maven.compiler.source>\n\t\t<maven.compiler.target>17</maven.compiler.target>\n\t</properties>\n</project>", "/astra/Base.astra": "agent Base {\n    types main { //belief predicated that agent can hold\n        formula floorplan(cartago.ArtifactId);\n        \n        formula warehouse(cartago.ArtifactId);\n        formula accessPoint(string, cartago.ArtifactId);\n\n        formula storagePoint(string, cartago.ArtifactId);\n\n        formula chargePoint(string, cartago.ArtifactId);\n        formula robot(string, cartago.ArtifactId);\n        formula at(string, string);\n\n        formula workstation(string, cartago.ArtifactId);\n\n        formula packagingPoint(string, cartago.ArtifactId);\n    }\n\n    // Requires the agent to be focussing on the robot with name (name)\n    inference at(string name, string location) :- //derived, is true when x on Y and cartago.focus(location) for cartago.at(..)\n            robot(name, cartago.ArtifactId rid) & cartago.at(location);\n\n    types comms { //messahe forumals for tranfer main to robot\n        formula transfer(string, string);\n        formula transferred(string, string);\n    }\n\n    module Cartago cartago;\n    module System S;\n    module modules.PropertyExtractor pe;\n    module Prelude P;\n\n    //******************************************************************************************\n    // FLOORPLAN\n    //******************************************************************************************\n    plan +!floorplan(cartago.ArtifactId aid) { //find existing floorplan or creare ,store as belief either eway\n        try {\n            cartago.lookupArtifact(\"floorplan\", aid);\n        } recover {\n            cartago.makeArtifact(\"floorplan\", \"artifacts.Floorplan\", cartago.params([]), aid);\n        }\n        +floorplan(aid);\n    }\n\n    plan +?locations(list locations) : //test goal to get all locations\n            floorplan(cartago.ArtifactId fpId) {\n        cartago.operation(fpId, observeProperty(\"locations\", cartago.ArtifactObsProperty prop));\n        locations = pe.listValues(prop);\n    }\n\n    plan +?free(string location) : //goal test to see if a location is free \n            floorplan(cartago.ArtifactId fpId) {\n        cartago.operation(fpId, isOccupied(location, boolean occupied));\n        if (occupied) S.fail();\n    }\n\n    //******************************************************************************************\n    // WAREHOUSE\n    //******************************************************************************************\n    plan +!warehouse(cartago.ArtifactId aid) { //inventory - lookup or create, similar to floorplan\n        try {\n            cartago.lookupArtifact(\"warehouse\", aid);\n        } recover {\n            cartago.makeArtifact(\"warehouse\", \"artifacts.Warehouse\", cartago.params([]), aid);\n        }\n        +warehouse(aid);\n    }\n\n    plan +!addToWarehouse(string item, int quantity) : warehouse(cartago.ArtifactId aid) { //calls add(..,..)\n        cartago.operation(aid, add(item, quantity));\n    }\n\n    //******************************************************************************************\n    // ACCESS POINT\n    //******************************************************************************************\n    plan +!accessPoint(string name, cartago.ArtifactId aid) :  //warehouse to floor bridge. clears acces point and links to gloorplan out-fp and warehouse out-1\n            warehouse(cartago.ArtifactId warehouseId) &\n            floorplan(cartago.ArtifactId fpId) {\n        try {\n            cartago.lookupArtifact(name, aid);\n        } recover {\n            cartago.makeArtifact(name, \"artifacts.AccessPoint\", cartago.params([]), aid);\n\n            // Install AP In Floorplan\n            cartago.linkArtifacts(aid, \"out-fp\", fpId);\n            cartago.operation(aid, install());\n\n            // Connect AP to Warehouse\n            cartago.linkArtifacts(aid, \"out-1\", warehouseId);\n        }\n        +accessPoint(name, aid);\n    }\n\n    plan +!available(string name, string type) : //achievement oal, tells AP to retrieve(tupe) from warehouse then verifies for arrival\n            accessPoint(name, cartago.ArtifactId aid) {\n        cartago.operation(aid, retrieve(type));\n        ?available(name, type);\n    }\n\n    plan +?available(string name, string type) : //test goal, reads Access Point's available. If type unbound, bind it. If bound not matches, fail\n            accessPoint(name, cartago.ArtifactId aid) {\n        cartago.operation(aid, observeProperty(\"available\", cartago.ArtifactObsProperty prop));\n        if (~pe.isBound(type)) {\n            type = pe.stringValue(prop);\n            cartago.println(type + \" is available at access point: \" + name);\n        } else if (type ~= pe.stringValue(prop))\n            S.fail();\n    }\n\n    //******************************************************************************************\n    // STORAGE POINT\n    //******************************************************************************************\n    plan +!storagePoint(string name, cartago.ArtifactId aid) : //Storage point - iintermediate buffer\n            floorplan(cartago.ArtifactId fpId) {\n        try {\n            cartago.lookupArtifact(name, aid);\n        } recover {\n            cartago.makeArtifact(name, \"artifacts.StoragePoint\", cartago.params([]), aid);\n\n            // Install AP In Floorplan\n            cartago.linkArtifacts(aid, \"out-fp\", fpId);\n            cartago.operation(aid, install());\n        }\n        +storagePoint(name, aid);\n    }\n\n    plan +?available(string name, string type) ://test goal, similar to access point, but for storage points\n            storagePoint(name, cartago.ArtifactId aid) {\n        cartago.operation(aid, observeProperty(\"available\", cartago.ArtifactObsProperty prop));\n        if (~pe.isBound(type)) {\n            type = pe.stringValue(prop);\n            cartago.println(type + \" is available at storage point: \" + name);\n        } else if (type ~= pe.stringValue(prop))\n            S.fail();\n    }\n\n    //******************************************************************************************\n    // PACKAGING POINT\n    //******************************************************************************************\n    plan +!packagingPoint(string name, cartago.ArtifactId aid) : //packaging - order delivery. create link to floorplan and install\n            floorplan(cartago.ArtifactId fpId) {\n        try {\n            cartago.lookupArtifact(name, aid);\n        } recover {\n            cartago.makeArtifact(name, \"artifacts.PackagingPoint\", cartago.params([]), aid);\n\n            // Install PP In Floorplan\n            cartago.linkArtifacts(aid, \"out-fp\", fpId);\n            cartago.operation(aid, install());\n        }\n\n        +packagingPoint(name, aid);\n    }\n\n    plan +!order(string name, list order) : //set order link like [\"apple-pie\"]\n            packagingPoint(name, cartago.ArtifactId aid) {\n        cartago.operation(aid, setOrder(order));\n    }\n\n    //******************************************************************************************\n    // ROBOT\n    //******************************************************************************************\n    plan +!robot(string name, cartago.ArtifactId rid) : //robot, physical transport. create charge point and link to floorplan\n            floorplan(cartago.ArtifactId fpId) {\n        try {\n            cartago.lookupArtifact(name, rid);\n            cartago.lookupArtifact(name+\"-charger\", cartago.ArtifactId rcId);\n            +chargePoint(name+\"-charger\", rcId);\n        } recover {\n            cartago.makeArtifact(name+\"-charger\", \"artifacts.RobotChargePoint\", cartago.params([800]), cartago.ArtifactId rcId);\n            +chargePoint(name+\"-charger\", rcId);\n\n            // Install AP In Floorplan\n            cartago.linkArtifacts(rcId, \"out-fp\", fpId);\n            cartago.operation(rcId, install(name));\n\n            cartago.lookupArtifact(name, rid);\n            cartago.linkArtifacts(rid, \"out-fp\", fpId);\n\n            cartago.println(name + \" CREATED\");\n        }\n        +robot(name, rid);\n    }\n\n    plan +?at(string name, string location) : //test goal, get robot location\n            robot(name, cartago.ArtifactId rid) {\n        cartago.operation(rid, observeProperty(\"at\", cartago.ArtifactObsProperty prop));\n        if (~pe.isBound(location)) {\n            location = pe.stringValue(prop);\n            cartago.println(name + \" is at location: \" + location);\n        } else if (location ~= pe.stringValue(prop))\n            S.fail();\n    }\n\n    plan +!at(string name, string location) : at(name, location) { } //if at point, do nothing\n\n    plan +!at(string name, string location) : //else check if location is free and move\n            robot(name, cartago.ArtifactId rid) {\n        ?free(location);\n        cartago.operation(rid, move(location));\n    }\n\n    plan +!holding(string name, string item) :  //calls load, verifies if picked up\n            robot(name, cartago.ArtifactId rid) {\n        cartago.operation(rid, load());\n        ?holding(name, item);\n        cartago.println(name + \" is holding \" + item);\n    }\n\n    plan +?holding(string name, string item) :\n            robot(name, cartago.ArtifactId rid) {\n        cartago.operation(rid, observeProperty(\"holding\", cartago.ArtifactObsProperty prop));\n        item = pe.stringValue(prop);\n    }\n\n    plan +!empty(string name) : //calls unload, verifies if unloaded\n            robot(name, cartago.ArtifactId rid) {\n        \n        ?holding(name, string item);\n\n        cartago.operation(rid, unload());\n        cartago.println(name + \" is no longer holding \" + item);\n    }\n\n    //******************************************************************************************\n    // WORKSTATION\n    //******************************************************************************************\n    plan +!workstation(string name, cartago.ArtifactId aid) : //create link, install - always create new\n            floorplan(cartago.ArtifactId fpId) {\n        cartago.makeArtifact(name, \"artifacts.Workstation\", cartago.params([]), aid);\n\n        // Install AP In Floorplan\n        cartago.linkArtifacts(aid, \"out-fp\", fpId);\n        cartago.operation(aid, install());    \n        +workstation(name, aid);\n    }\n\n    plan +!configure(string name, list inputs, string output, long duration) : //set input/output/duration on workstation.\n            workstation(name, cartago.ArtifactId wid) {\n        \n        // DO ACTUAL CONFIGURATION HERE...\n        cartago.operation(wid, configure(inputs, output, duration));\n        cartago.println(name + \" is configured (inputs: \" + inputs + \"; output: \" + output + \")\" );\n    }\n\n    plan +?inputsNeeded(string name, list inputs) : //test goal, read what ingedients missing\n            workstation(name, cartago.ArtifactId wid) {\n        cartago.operation(wid, observeProperty(\"inputsNeeded\", cartago.ArtifactObsProperty prop));\n        inputs = pe.listValues(prop);\n    }\n\n    plan +?state(string name, string state) : //test goal, read state -> idle.ready/active/done\n            workstation(name, cartago.ArtifactId wid) {\n        cartago.operation(wid, observeProperty(\"state\", cartago.ArtifactObsProperty prop));\n        if (~pe.isBound(state))\n            state = pe.stringValue(prop);\n        else if (state ~= pe.stringValue(prop))\n            S.fail();\n    }\n\n    plan +!operate(string name) : //production sequence, check state is ready, call operate(), do every 0.5sec if state is not done\n            workstation(name, cartago.ArtifactId ws1Id) {\n        // Check workstation is in correct state...\n        ?state(name, \"ready\");\n\n        // Operate\n        cartago.operation(ws1Id, operate());\n\n        // Wait for operation to complete\n        //?state(\"ws1\", string state);\n        ?state(name, string state);\n        while (state ~= \"done\") {\n            S.sleep(500);\n            //?state(\"ws1\", string state2);\n            ?state(name, string state2);\n            state = state2;\n        }\n\n        //cartago.println(\"ws1 is: \" + state);\n        cartago.println(name + \" is: \" + state);\n    }\n}", "/astra/FactoryManager.astra": "// agent FactoryManager extends Base, FIPACNInitiator { //step 2. call for proposal cfp broadcast, bid collection, accept/reject\nagent FactoryManager extends Base, TransportCoordination { //step 8. removed FIPACNInitiator, now uses TransportCoordination\n    //step 8. factorymanager is now production planner  that delagates transport to a robot coordinator\n    //step 8. doesnt run CNP directly anymore, sends FIPA request to the transport coordiantor instead\n\n    types manager {\n         formula recipe(string, list, string); //step 2. workstation what it makes and needs\n        formula contract_counter(int); //step 2.  auto increment auction  contracts t0, t1..\n        formula order_time(string, long); //step 6. time taken per order (ppName, elapsed ms)\n        formula best_time(long); //step 7. fastest order.\n        formula worst_time(long); //step 7. slowest order\n    }\n\n    initial contract_counter(0);\n\n    rule +!main(list args) {\n        cartago.link();\n\n        //step 2. linking artifacts floorplan, warehouse, access points, storage, packaging, workstations\n        !floorplan(cartago.ArtifactId _);\n        !warehouse(cartago.ArtifactId _);\n        !accessPoint(\"ap1\", cartago.ArtifactId _);\n        !accessPoint(\"ap2\", cartago.ArtifactId _);\n         !storagePoint(\"sp1\", cartago.ArtifactId _);\n        !packagingPoint(\"pp1\", cartago.ArtifactId _);\n\n        cartago.lookupArtifact(\"ws1\", cartago.ArtifactId ws1Id);\n        +workstation(\"ws1\", ws1Id);\n        cartago.lookupArtifact(\"ws2\", cartago.ArtifactId ws2Id);\n        +workstation(\"ws2\", ws2Id);\n\n        // forall(string name : args) { //step 2. registers evert robot name that passed from Main.setMainGoal as CNP paticipant\n        //     +participant(name);\n        // }\n        //step 8.  store transport coordinator names from  Main.setMainGoal args\n        //step 8. args = [\"r1\"] the robot assinged as transport coordinator\n        forall(string name : args) {\n            +transport_coordinator(name); //step 8. register as coordinator instead of participant\n        }\n\n        S.sleep(3000); //step 2. sleep 3s\n        cartago.println(\"=== FactoryManager ready ===\");\n\n        //step 2. declare 2 recipes\n        +recipe(\"ws1\", [\"flour\", \"butter\"], \"pastry\");\n        +recipe(\"ws2\", [\"apples\", \"pastry\"], \"apple-pie\");\n\n        //step 2. ofirst apple pie\n        !fulfil_order(\"pp1\", [\"apple-pie\"]);\n    }\n\n    rule +!fulfil_order(string ppName, list items) :\n            packagingPoint(ppName, cartago.ArtifactId ppId) {\n        long start = pe.currentTimeMillis(); //step 7. extra record start time\n        forall(string item : items) { // step 2. foreach on order list call the below, when all items arrive, run deliver\n            !produce_and_deliver(item, ppName);\n        }\n        cartago.operation(ppId, deliver());\n        long elapsed = pe.currentTimeMillis() - start; //step 7. calculate elapsed time\n        +order_time(ppName, elapsed); //step 7. extra store per-order time\n        !update_stats(elapsed); //step 7. extra update min/max\n        cartago.println(\"=== Order at \" + ppName + \" FULFILLED in \" + elapsed + \"ms ===\");\n    }\n\n    //step 7. extra update best/worst time \u2014 first order sets both\n    rule +!update_stats(long elapsed) : best_time(long best) {\n        query(worst_time(long worst)); //step 7. extra  stores worst current time into wirst\n        if (elapsed < best) { -+best_time(elapsed); } //if faster update the belief\n        if (elapsed > worst) { -+worst_time(elapsed); } //if slower update the belief\n        query(best_time(long b)); //step 7. extra  retreive best time\n        query(worst_time(long w)); //step 7. extra  retreive worst time\n        cartago.println(\"  Stats: best=\" + b + \"ms, worst=\" + w + \"ms\");\n    }\n\n    rule +!update_stats(long elapsed) { //step 7. extra first order \u2014 no previous stats\n        +best_time(elapsed); //step 7. extra  initial\n        +worst_time(elapsed);\n        cartago.println(\"  Stats: best=\" + elapsed + \"ms, worst=\" + elapsed + \"ms\");\n    }\n\n    //?state(wsName, string s0); s0 idle, s1 ready, s2 active, s3 done\n    //means end reasoning \n    rule +!produce_and_deliver(string item, string destination) : \n            recipe(string wsName, list inputs, item) { //step 2. when recipe(string wsName, list inputs, item) exists ,\n             //step 2. it can be manuifactured, supplied to workstations, operated and transported to destinations\n        cartago.println(\"Producing \" + item + \" at \" + wsName);\n        forall(string input : inputs) {\n            !supply_input(input, wsName);\n        }\n        !operate(wsName);\n        !cnp_transport(wsName, destination);\n    }\n\n    rule +!produce_and_deliver(string item, string destination){ //step 2. no recipe, it is raw material, \n        !available(\"ap1\", item); //step 2. fetch it from warehouse\n        !cnp_transport(\"ap1\", destination); //step 2. transport it\n    }\n\n    //recursive sub production\n    rule +!supply_input(string input, string wsName) :\n            recipe(string subWs, list subInputs, input) { //step 5. if recipe(string subWs, list subInputs, input) exists \n        cartago.println(\"Sub-production needed: \" + input); //step 5. input is manufactured \n        !produce_and_deliver(input, \"sp1\"); //step 5. call recurcively to the storage then transpoty ftom storage to the workstation\n        !cnp_transport(\"sp1\", wsName); //step 5. then move pastry from sp1 to workstation\n    }\n    //no recursion\n    rule +!supply_input(string input, string wsName)   { //step 5. raw material, fetch from warehouse , transport to workstation\n         !available(\"ap1\", input);\n        !cnp_transport(\"ap1\", wsName);\n    }\n\n    // rule +completed(string id, true) : awarded(id, string winner) { //step 2. REMOVED not using CNP directly anymore\n    //     cartago.println(winner + \" awarded contract \" + id + \" for completing the job\");\n    // }\n\n    //step 8. recieves transport_done from coordinator after  the sub-CNP completes\n    rule @message(inform, string sender, transport_done(string id)) {\n        +transport_done(id); //step 8. store completion belief, wakes up the wait() in cnp_transport\n    }\n\n    //step 8.  recieves failure from coordinator if sub-CNP fails\n    rule @message(failure, string sender, coordinate_transport(string id, string from, string to)) {\n        cartago.println(\"Transport coordinator \" + sender + \" failed for \" + id); //step 8. log the failure\n    }\n\n    // rule +!cnp_transport(string from, string to) { //step 2. auction wrapper - ORIGINAL BELOW\n    //     query(contract_counter(int count)); //step 2. gets the current value of the counter\n    //     -+contract_counter(count + 1); //step 2. increments the counter \n    //     string cid = \"t\" + count; //step 2. generates a unique id for the contract\n    //\n    //     +contract(cid, \"transport\", [from, to], 5000); //step 2. creates a new contract with the generated id and parameters\n    //\n    //     boolean ok = false;\n    //     try {\n    //         !awarded(cid, string winner); //step 2. sends the contract to all participants and waits for bids\n    //         cartago.println(cid + \" awarded to \" + winner); //step 2. winner selected\n    //         ok = true;\n    //     } recover { //fallback \n    //         -contract(cid, \"transport\", [from, to], 5000); //step 2. removes the contract\n    //     }\n    //\n    //     if (ok == false) { //step 5. if no bids recieved\n    //         cartago.println(cid + \" no bids, retrying...\"); //step 5. retry\n    //         S.sleep(3000); //step 5. wait 3 sec\n    //         !cnp_transport(from, to); //step 5. recursive retry\n    //     } else { //step 5. waitining timeout prevents indefinite waiting\n    //         wait(completed(cid, true), 60000); //step 5. 60 sec rimeout \n    //         if (~completed(cid, true))  {\n    //             S.fail(); //step 5. fail if robot never reponds back\n    //         }\n    //         -completed(cid, true); //cleanup the belief\n    //     }\n    // }\n\n    //step 8. rewritten to delagate transport to robot-level coordinator via FIPA request\n    //step 8. instead of running CNP directly it sends  request to the transport coordinator (r1)\n    //step 8. then r1 runs CNP among its worker robots r2, r3\n    rule +!cnp_transport(string from, string to) {\n        query(contract_counter(int count)); //step 2. gets the current value of the counter\n        -+contract_counter(count + 1); //step 2. increments the counter \n        string cid = \"t\" + count; //step 2. generates a unique id for the contract\n\n        //step 8. delagate to transport coordinator via FIPA request (was direct CNP auction)\n        query(transport_coordinator(string coordinator)); //step 8. get the coordinator name\n        cartago.println(cid + \" delegating transport [\" + from + \" -> \" + to + \"] to \" + coordinator);\n        send(request, coordinator, coordinate_transport(cid, from, to)); //step 8. send the request to coordinator\n\n        //step 8. wait for coordinator to report back completion\n        wait(transport_done(cid), 60000); //step 8. 60sec timeout\n        if (~transport_done(cid)) {\n            cartago.println(cid + \" transport coordination timed out, retrying...\");\n            S.sleep(3000); //step 8. wait 3sec before retrying\n            !cnp_transport(from, to); //step 8. recursive retry like before\n        } else {\n            cartago.println(cid + \" transport completed successfully\");\n            -transport_done(cid); //step 8. cleanup the belief\n        }\n    }\n}\n", "/astra/FIPACNInitiator.astra": "agent FIPACNInitiator extends FIPAContractNet { //step 1. auctioneer, braodcast job to robots, waits for bids, picks hihest, tells winner go for it, records outcome. FactoryManager.astra will extend this and call !awarded(..) when robot has to transport a task\n    types cnp_initiator {\n        formula participant(string);\n        formula awarded(string, string);\n        formula best_bid(string, string, int); \n         formula completed(string, boolean);\n    }\n\n    rule +!awarded(string id, string winner) : awarded(id, string awardee) { //step 1. already awarded, just return wwinner\n        winner = awardee;\n    }\n\n    rule +!awarded(string id, string winner) : contract(id, string type, list params, int deadline) { //step 1. run auction\n         foreach(participant(string participant)) { //step 1. broadcast cfp call to participant to all participants\n            send(cfp, participant, contract(id, type, params, deadline)); //step 1. send contract details\n        }\n\n        S.sleep(deadline); //step 1. give time to bid\n\n        foreach(bid(id, string participant, int value)) { //step 1. loop to all and find the best\n             !best_bid(id, participant, value);\n        }\n\n        query(best_bid(id, string best_bidder, int best_bid_val)); //step 1. select best and send accept\n        send(accept-proposal, best_bidder, bid(id, best_bidder, best_bid_val));\n\n        foreach (participant(string name) & bid(id, name, int bidVal) & (name ~= best_bidder)) { //step 1. rject the rest\n            send(reject-proposal, name, bid(id, name, bidVal));\n        }\n\n        +awarded(id, best_bidder); //step 1. store awarded id and return winner name\n        winner = best_bidder;\n    }\n\n    rule +!best_bid(string id, string bidder, int value) : //step 1. update the traker\n            best_bid(id, string best_bidder, int best_value) { //step 1. if best bid exists already\n        if (value > best_value) { //step 1. new one better then best\n            -+best_bid(id, bidder, value); //step 1. replace with new\n        }\n    }\n\n    rule +!best_bid(string id, string bidder, int value) : //step 1. first bid, then it is the best ,because it cannot compare\n            contract(id, string type, list params, int deadline) {\n        +best_bid(id, bidder, value);\n    }\n\n    rule @message(propose, string sender, bid(string id, sender, int value)) : participant(sender) { //step 1. recieve a bid, only from register participant\n         +bid(id, sender, value); //step 1. store bid\n    }\n\n    rule @message(inform, string sender, fulfilled(string id, string type, list params)) { //step 1. compelte task\n        !completed(id, true); //step 1. winnign robot finished job\n    }\n\n    rule @message(failure, string sender, contract(string id, string type, list params, int deadline)) { //step 1. failure to complete\n        !completed(id, false); //step 1. mark as failure\n    }\n\n    rule +!completed(string id, boolean outcome) {    //step 1. record outcome\n        +completed(id, outcome);//step 1. default: store the result as a belief. FactoryManager.astra later will override this to react.\n    }\n}\n", "/astra/FIPACNParticipant.astra": "agent FIPACNParticipant extends FIPAContractNet { //step 1. biider\n    types cnp_participant {\n        formula accepted(string, string);\n         formula rejected(string, string);\n    }\n\n    rule @message(cfp, string sender, contract(string id, string type, list params, int deadline)) { //step 1. get protocol for proosals\n        +contract(id, type, params, deadline); //step 1. says i need a robot got this job, then stores it.\n        \n        try {\n            !bid(id, string name, int value); //step 1. try bid\n            send(propose, sender, bid(id, name, value)); //step 1. send propose if bid is successfull\n        } recover {\n             send(refuse, sender, contract(id, type, params, deadline)); //step 1. send refuse if bid fails\n        }\n    }\n\n    //step 1. S.name() for itself proposals\n    rule @message(accept-proposal, string sender, bid(string id, S.name(), int value)) : contract(id, string type, list params, int deadline) {\n        +accepted(id, sender); //step 1. you won. reconds the accept. \n        \n        try {\n            !fulfil(id, type, params); //step 1. try to do real work. \n            send(inform, sender, fulfilled(id, type, params)); //step 1. if success send inform(\"done\")\n        } recover {\n            send(failure, sender, contract(id, type, params, deadline)); //step 1. if failure send failure\n        }\n    }\n\n    rule @message(reject-proposal, string sender, bid(string id, S.name(), int value)) : contract(id, string type, list params, int deadline) {\n        +rejected(id, sender); //step 1. sorry you lost, record the rejection\n    }\n\n    rule +!bid(string id, string name, int value) { //pick packaging\n        !generate_bid(id, int my_value); //step 1. make a numberic value, \n         name = S.name(); //step 1. package with the robots name \n        value = my_value; \n        +bid(id, name, value); // step 1. store as belief\n    }\n\n    //step 1. the above 2 to be used by RobotWorker\n    rule +!generate_bid(string id, int value) : contract(id, string type, list params, int deadline) { //step 1. designed to be overriden by Robotwoeker\n        S.fail(); //step 1. default is S.fail(). e.g. return current battery level as tge bid, more energy better bid.\n    }\n\n    rule +!fulfil(string id, string type, list params) { //step 1. designed to be overriden by Robotwoeker\n      S.fail(); //step 1. default is S.fail(). will be overriden with transport. move to pickup-> load-> move to dropdown->unload\n    }\n}\n", "/astra/FIPAContractNet.astra": "agent FIPAContractNet {\n    module System S;\n\n    types cnp_shared { //step 1. create contract nec shared vocabulary \n        formula contract(string, string, list, int);\n         formula bid(string, string, int);\n\n        formula fulfilled(string, string, list);\n    }\n}\n", "/astra/Main.astra": "agent Main extends Base { //factory manager\n\n    rule +!main(list args) { //sequence of order fullfilment \n        cartago.startService();\n    \tcartago.link();\n        \n        !setup();\n\n        !floorplan(cartago.ArtifactId _);\n\n        // S.createAgent(\"r1\", \"Robot\");\n        // S.createAgent(\"r1\", \"RobotWorker\"); //step 4  Robot->RobotWorker\n        // S.createAgent(\"r2\", \"RobotWorker\");//step 4  nil->RobotWorker\n        S.createAgent(\"r1\", \"RobotWorker\"); //step 8. this one will be  the transport coordinator\n        S.createAgent(\"r2\", \"RobotWorker\"); //step 8. worker\n        S.createAgent(\"r3\", \"RobotWorker\"); //step 8. worker\n\n        //step 8. r1 is assinged as transport coordinator, its participants are r2 and r3\n        //step 8. r1 must not be in its own participant list (no self bidding)\n        S.setMainGoal(\"r1\", [\"r2\", \"r3\"]); //step 8.  r1 coordinates r2, r3\n\n        S.createAgent(\"manager\", \"FactoryManager\"); //step 4  make FactoryManager\n        // S.setMainGoal(\"manager\", [\"r1\", \"r2\"]); //step 4 manager goal - ORIGINAL\n        S.setMainGoal(\"manager\", [\"r1\"]); //step 8. manager delagates to r1 the transport coordinator\n\n        // You can discover a list of the current locations by examining the floorplan...\n        // ?locations(list L);\n        // cartago.println(\"L=\" + L);\n\n        // Example: Robot r1 is assigned to ap1 and ws1. ws1 can be used to make apple pies.\n        //          r1 retrieves the necessary ingredients and then creates the apple pie\n        //          it should drop the apple pie to the packaging point for delivery...\n        \n        // Retrieve an item from the warehouse and place at ap1\n        // !available(\"ap1\", \"apples\"); //1. fetch apples from warehouse to access point\n                \n        // ROBOT: Move item from ap1 to ws1\n        // !transfer(\"r1\", \"ap1\", \"ws1\"); //2. transfer from access point to workstation\n\n        // Example of retrieving an item based on the\n        // inputsNeeded property of the workstation.\n        // ?inputsNeeded(\"ws1\", list items); //ask the workstation what is missing and fetch it, roboto delivers it\n        // !available(\"ap1\", P.headAsString(items));\n\n        // ROBOT: Move item from ap1 to ws1\n        // !transfer(\"r1\", \"ap1\", \"ws1\");\n\n        // Check what the state of ws1 is (not a robot operation)\n        // ?state(\"ws1\", string state);\n        // cartago.println(\"ws1 is: \" + state);\n\n        //---------------------\n        // Now, operate the workstation (not the robot)\n        // !operate(\"ws1\"); //run workstayion, waits until \"done\"\n        //robot moves output from workstation->storage->packaging point\n\n        // ROBOT: Pickup the output when finished...\n        // !transfer(\"r1\", \"ws1\", \"sp1\"); //coordination protocol\n\n        // ?available(\"sp1\", string spItem);\n\n        // !transfer(\"r1\", \"sp1\", \"pp1\");\n    }\n\n    // plan +!transfer(string name, string from, string to) { //sends requesys, waits transferred, then drops belief\n    //     send(request, name, transfer(from, to));\n    //     wait(transferred(from, to));\n    //     -transferred(from, to);\n    // }\n\n    // plan @message(inform, string sender, transferred(string from, string to)) { //transfer vallbaclk\n    //     cartago.println(sender + \" is at location: \" + to);\n    //     +transferred(from, to); //when robot send inform with transferred(from,to) belief is created\n    // }\n\n    rule +!setup() { //init factory\n        !warehouse(cartago.ArtifactId wId);\n        // !addToWarehouse(\"apples\", 2);\n        !addToWarehouse(\"apples\", 10); //step 4 2->10\n        !addToWarehouse(\"flour\", 10); //step 4 nil->10\n        !addToWarehouse(\"butter\", 10); //step 4 nil->10\n        // !addToWarehouse(\"pastry\", 10); //stocks to warehouse\n\n        !floorplan(cartago.ArtifactId fpId);\n\n        !accessPoint(\"ap1\", cartago.ArtifactId ap1Id); //connects warehouse to floorplan\n        !accessPoint(\"ap2\", cartago.ArtifactId ap2Id);\n\n        !storagePoint(\"sp1\", cartago.ArtifactId sp1Id);\n\n        !packagingPoint(\"pp1\", cartago.ArtifactId pp1Id);\n        !order(\"pp1\", [\"apple-pie\"]); //set order \"apple-pie\"\n\n        !robot(\"r1\", cartago.ArtifactId r1Id);\n        !robot(\"r2\", cartago.ArtifactId r2Id); //2 robots\n        !robot(\"r3\", cartago.ArtifactId r3Id); //step 8. 3rd robot for dynamic cnp\n        \n        !workstation(\"ws1\", cartago.ArtifactId ws1Id);\n        // !configure(\"ws1\", [\"apples\", \"pastry\"], \"apple-pie\", 2000l); //configure workstation\n        !configure(\"ws1\", [\"flour\", \"butter\"], \"pastry\", 2000l); //step 4 flour, butter -> pastry\n\n        !workstation(\"ws2\", cartago.ArtifactId ws2Id); //step 4 \n        !configure(\"ws2\", [\"apples\", \"pastry\"], \"apple-pie\", 2000l); //step 4: apples, pastry-> apple pie\n\n\n        cartago.println(\"=== Factory setup complete ===\"); //step 4\n    }\n}", "/astra/Robot.astra": "//not used anymore\nagent Robot extends Base { //working agent, inhertis Base\n    initial !init();\n\n    plan +!init() { //constructor\n    \tcartago.link(); //connect to cartago\n\n        !floorplan(cartago.ArtifactId _); //inherit plan floorplan\n        !robot(S.name(), cartago.ArtifactId rid); //inherit plan robot\n        cartago.focus(rid); //focus on robot. importanty\n\n        // Sleep for a second to let the property\n        // updates get processed...\n        S.sleep(1000);\n    }\n\n    plan @message(request, string sender, transfer(string from, string to)) { //transfer execution\n        cartago.println(\"received request for transfer from: \"  + from + \" to: \" +to);\n\n        !at(S.name(), from); //go to pickup location    \n        !holding(S.name(), string _); // pickup is there\n        !at(S.name(), to);//move to drop location\n        !empty(S.name()); //put item down\n\n        cartago.println(\"completed transfer from: \"  + from + \" to: \" +to);\n\n        // Example Charging Step...\n        !at(S.name(), S.name()+\"-charger\"); //charge\n        ?robot(S.name(), cartago.ArtifactId rid);\n        cartago.println(\"Charging...\");\n        cartago.operation(rid, charge());\n        cartago.println(\"Charged...\");\n\n        send(inform, sender, transferred(from, to)); //notify transfer completed\n    }\n\n\n}", "/astra/RobotWorker.astra": "// agent RobotWorker extends Base, FIPACNParticipant { //step 3. robots are participants - ORIGINAL\nagent RobotWorker extends Base, FIPACNParticipant, FIPACNInitiator, TransportCoordination { //step 8. dual role now, participant + initiator\n//step 8.  extends both FIPACNParticipant (worker/bidder) and FIPACNInitiator (coordinator/auctioneer)\n//step 8. this shows dynamic CNP role adoption, a robot can act as contractor in one conversaiton\n//step 8. and as coordinator in another conversaiton. roles are not mixed within the same contract\n//step 3. receives cfp, sends propose/refuse, handles accept-proposal/reject-proposal\n    types robot_private {\n        formula busy(boolean); //step 3. tracks id robot is doing a task\n        formula is_coordinator(boolean); //step 8. true if robot is  assigned as transport coordinator\n    }\n\n    initial busy(false); //step 3. init idle\n    initial is_coordinator(false); //step 8. not a coordinator by defualt\n    initial !init();\n\n    rule +!init() {\n    \tcartago.link();\n        !floorplan(cartago.ArtifactId _); //step 3. looks up factory floorplan\n        !robot(S.name(), cartago.ArtifactId rid); //step 3. looks up this robot by id e.g. r1\n        cartago.focus(rid); //step 3. subscribe\n        S.sleep(1000); //step 3. needs time 1 sec\n        //step 3. Now Robot waited for request messages from Main. RobotWorker initialises itseld and participated in auction automaticly\n    }\n\n    //step 8. recieves participant list from Main.setMainGoal (only coordinator robots get this)\n    //step 8. e.g. S.setMainGoal(\"r1\", [\"r2\", \"r3\"]) so r1 gets +!main([\"r2\", \"r3\"])\n    rule +!main(list args) {\n        forall(string name : args) {\n            +participant(name); //step 8. register worker robots as  CNP participants (from FIPACNInitiator)\n        }\n        -+is_coordinator(true); //step 8. mark this robot as transport coordinator\n        cartago.println(S.name() + \" is now transport coordinator for: \" + args);\n    }\n\n    //step 8. coordinator role - recieves transport delegation from FactoryManager via FIPA request\n    //step 8. runs a CNP auction among  the registered worker participants (r2, r3)\n    //step 8. reports result back to FactoryManager with inform or failure\n    rule @message(request, string sender, coordinate_transport(string cid, string from, string to)) :\n            is_coordinator(true) { //step 8. only handle if this robot is the coordinator\n        cartago.println(S.name() + \" coordinating \" + cid + \" [\" + from + \" -> \" + to + \"]\");\n\n        //step 8. create cnp contract and run auction using inherited FIPACNInitiator rules\n        +contract(cid, \"transport\", [from, to], 5000); //step 8.  create the contract belief\n\n        boolean ok = false;\n        try {\n            !awarded(cid, string winner); //step 8. from FIPACNInitiator - broadcasts cfp,  collects bids, picks winner\n            cartago.println(S.name() + \" sub-contracted \" + cid + \" to \" + winner);\n            ok = true;\n        } recover {\n            -contract(cid, \"transport\", [from, to], 5000); //step 8. cleanup  on failure\n        }\n\n        if (ok == false) { //step 8. no bids recieved from workers\n            cartago.println(S.name() + \": \" + cid + \" no bids from workers, retrying...\");\n            S.sleep(3000); //step 8. wait 3sec\n            //step 8. retry by recreating the contract\n            +contract(cid, \"transport\", [from, to], 5000);\n            try {\n                !awarded(cid, string winner2);\n                cartago.println(S.name() + \" sub-contracted \" + cid + \" to \" + winner2 + \" (retry)\");\n                ok = true;\n            } recover {\n                -contract(cid, \"transport\", [from, to], 5000);\n                send(failure, sender, coordinate_transport(cid, from, to)); //step 8. report failure back to manager\n            }\n        }\n\n        if (ok == true) { //step 8.  wait for the winner robot to complete transport\n            wait(completed(cid, true), 60000); //step 8. 60sec timeout\n            if (~completed(cid, true)) {\n                cartago.println(S.name() + \": \" + cid + \" transport timed out\");\n                send(failure, sender, coordinate_transport(cid, from, to)); //step 8. report failure back\n            } else {\n                -completed(cid, true); //step 8. cleanup belief\n                cartago.println(S.name() + \": \" + cid + \" transport done, reporting to \" + sender);\n                send(inform, sender, transport_done(cid)); //step 8. report sucess to FactoryManager\n            }\n        }\n    }\n\n    //step 8.  override to log when coordinator gets completion from a worker\n    rule +completed(string id, true) : awarded(id, string winner) & is_coordinator(true) {\n        cartago.println(S.name() + \": worker \" + winner + \" completed contract \" + id);\n    }\n\n    //step 5. overide FIPACNParticipant. multiple Robots COMPETE on energy. gigher energy = better bid = winner\n    rule +!generate_bid(string id, int value) : \n            contract(id, \"transport\", list params, int deadline) & //step 5. context: contract(id, \"transport\", list params, int deadline) & busy(false)          \n            busy(false) { //step 5. only on trasport contracts and ony when not busy\n        ?robot(S.name(), cartago.ArtifactId rid);\n        cartago.operation(rid, observeProperty(\"energy\", cartago.ArtifactObsProperty prop));\n        int energy = pe.intValue(prop); //step 5. read robots energy\n        if (energy < 400) { //step 5 if energy <400 refuse \n            S.fail();\n        }\n        value = energy; //Step 5. Bid is energy e.g. r1(800) beats r2(600)\n        -+busy(true);\n    }\n\n    rule +!generate_bid(string id, int value) : busy(true) { //step 5. if busy, refuse\n        S.fail(); //step 5. failure goes to !bid-> try/recover->send(refuse,sender..) FIPACNParticipant->@message(cfp..\n    }\n\n    rule +rejected(string id, string sender) {\n        -+busy(false); //step 5. if rejected, FIPACNInitiator had sent reject-proposa, so it sends it gets busy false to be bid(able) again\n    }\n\n    rule +!goto(string name, string location) : at(name, location) { } //step 3. retry. if there already, do nothing\n\n    \n    //step 5 zone contention\n    rule +!goto(string name, string location) :\n            robot(name, cartago.ArtifactId rid) { \n        try {\n            ?free(location); //step 5. check is the zone is unoccupied. Constraint 1 ribit per zone\n            cartago.operation(rid, move(location)); //step 3. move\n        } recover {\n            S.sleep(500); //step 5. wait 0.5 retry recursively\n            !goto(name, location); \n        }\n    }\n\n    rule +!fulfil(string id, \"transport\", list params) { //step 3. overide. when accept-proposal recieved, the params have [from, to]\n        string from = P.headAsString(params);\n        string to = P.headAsString(P.tail(params));\n\n        //step 3. go to transport\n        !goto(S.name(), from); //step 3. move\n        !holding(S.name(), string _); //step 3. hold\n        !goto(S.name(), to); //step 3. move\n        !empty(S.name()); //step 3. release\n\n        //step 5. return to charger - smart charging\n        !goto(S.name(), S.name()+\"-charger\"); //step 5. go home e.g \"r1-charger\"\n        ?robot(S.name(), cartago.ArtifactId rid);\n        cartago.operation(rid, observeProperty(\"energy\", cartago.ArtifactObsProperty prop));\n        int energy = pe.intValue(prop); //step 3. Read energy\n        if (energy < 400) { //step 3. if low charge\n            cartago.operation(rid, charge());\n            cartago.operation(rid, observeProperty(\"energy\", cartago.ArtifactObsProperty prop2));\n            int energy2 = pe.intValue(prop2);\n            //step . full transport = move+load+move+unload= 100+50+100+50=300. Plus move to charger 100, so 400 threshold it needs\n            if (energy2 < 400) {\n                cartago.operation(rid, charge());\n            }\n        }\n\n        -+busy(false); //step 3. releasem to ve ready for next auction\n    } //step 3. when !fulfil done, FIPACNParticipant sends inform(fulfilled()) to coordinator which triggers +completed(cid, true) \n}\n", "/astra/TransportCoordination.astra": "agent TransportCoordination { //step 8. shared types for  manager to coordinator communication\n    //step 8. like SharedG/SharedA/SharedP from the hierarchy exapmle\n    types transport_coord {\n        formula coordinate_transport(string, string, string);  //step 8. (id, from, to) request to coordiante transport\n        formula transport_done(string);                         //step 8. (id) transport coordination completd\n        formula transport_coordinator(string);                  //step 8. (name) name of the coordinator  agent\n    }\n}\n", "/java/artifacts/AccessPoint.java": "package artifacts;\n\nimport cartago.ARTIFACT_INFO;\nimport cartago.Artifact;\nimport cartago.LINK;\nimport cartago.OPERATION;\nimport cartago.OUTPORT;\nimport cartago.OpFeedbackParam;\nimport cartago.OperationException;\nimport model.Item;\n\n@ARTIFACT_INFO(outports = { @OUTPORT(name=\"out-1\"), @OUTPORT(name=\"out-fp\") })\npublic class AccessPoint extends Artifact {\n    public static final String NONE = \"none\";\n    private Item item;\n\n    @OPERATION\n    public void init() {\n        defineObsProperty(\"available\", NONE);\n    }\n\n    @OPERATION\n    public void install() throws OperationException {\n        execLinkedOp(\"out-fp\", \"install\", getId(), new String[] {\"available\"});\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"available\", NONE);\n    }\n\n    @OPERATION\n    public void retrieve(String type) throws OperationException {\n        OpFeedbackParam<Item> item = new OpFeedbackParam<>();\n        execLinkedOp(\"out-fp\", \"setStatus\", getId().getName(), \"retrieving\");\n        execLinkedOp(\"out-1\", \"retrieve\", type, item);\n        updateObsProperty(\"available\", type);\n        execLinkedOp(\"out-fp\", \"setStatus\", getId().getName(), \"idle\");\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"available\", type);\n        this.item = item.get();\n    }\n\n    @LINK\n    public void take(OpFeedbackParam<Item> item) throws Exception {\n        if (this.item == null) throw new Exception(\"Access Point \" + getId().getName() + \": NO ITEM AVAILABLE\");\n\n        updateObsProperty(\"available\", NONE);\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"available\", NONE);\n        item.set(this.item);\n        this.item = null;\n    }\n}", "/java/artifacts/Floorplan.java": "package artifacts;\n\nimport java.util.HashMap;\nimport java.util.Map;\n\nimport cartago.Artifact;\nimport cartago.ArtifactId;\nimport cartago.LINK;\nimport cartago.OPERATION;\nimport cartago.OpFeedbackParam;\nimport model.Location;\nimport ui.PlantViewer;\nimport ui.RobotPanel;\nimport ui.ZonePanel;\n\npublic class Floorplan extends Artifact {\n    private Map<String, Location> locations = new HashMap<>();\n    private PlantViewer viewer;\n    private Map<String, ZonePanel> zones = new HashMap<>();\n    private Map<String, RobotPanel> robots = new HashMap<>();\n\n    @OPERATION\n    public void init() {\n        defineObsProperty(\"locations\", locations.keySet());\n        viewer = new PlantViewer();\n    }\n\n    @LINK\n    public void install(cartago.ArtifactId id, String[] customFields) {\n        locations.put(id.getName(), new Location(id));\n        updateObsProperty(\"locations\", locations.keySet());\n        ZonePanel zonePanel = viewer.addZone(id.getName(), id.getArtifactType());\n        for (String field : customFields) {\n            zonePanel.addCustomField(field, \"\");\n        }\n        zones.put(id.getName(), zonePanel);\n    }\n\n    @LINK\n    public void location(String name, OpFeedbackParam<ArtifactId> id) {\n        id.set(locations.get(name).id());\n    }\n\n    @LINK\n    public void setStatus(String name, String status) {\n        zones.get(name).setStatus(status);\n    }\n\n    @LINK\n    public void setRobotField(String name, String key, String value) {\n        robots.get(name).setField(key, value);\n    }\n\n    @LINK\n    public void setCustomField(String name, String custom, String value) {\n        zones.get(name).setCustomField(custom, value);\n    }\n\n    @LINK\n    public void move(String name, String from, String to) throws Exception {\n        Location target = locations.get(to);\n        Location source = locations.get(from);\n\n        if (target.isOccupied()) throw new Exception(\"Target Location is Occupied: \" + to);\n        source.occupancy(null);\n        zones.get(from).setAvailable(\"empty\");\n        Thread.sleep(2000);\n        target.occupancy(name);\n        zones.get(to).setAvailable(name);\n        robots.get(name).setField(\"at\", to);\n    }\n\n    @LINK\n    public void place(String name, String to) throws Exception {\n        Location target = locations.get(to);\n\n        if (target.isOccupied()) throw new Exception(\"Target Location is Occupied: \" + to);\n        target.occupancy(name);\n        zones.get(to).setAvailable(name);\n        RobotPanel robotPanel = viewer.addRobot(name);\n        robots.put(name, robotPanel);\n        robotPanel.setField(\"at\", to);\n\n    }\n\n    @OPERATION\n    public void isOccupied(String name, OpFeedbackParam<Boolean> occupied) {\n        Location location = locations.get(name);\n        occupied.set(location.isOccupied());\n    }\n}\n", "/java/artifacts/PackagingPoint.java": "package artifacts;\n\nimport java.util.ArrayList;\nimport java.util.LinkedList;\nimport java.util.List;\n\nimport cartago.ARTIFACT_INFO;\nimport cartago.Artifact;\nimport cartago.LINK;\nimport cartago.OPERATION;\nimport cartago.OUTPORT;\nimport cartago.OperationException;\nimport model.Item;\n\n@ARTIFACT_INFO(outports = { @OUTPORT(name=\"out-1\"), @OUTPORT(name=\"out-fp\") })\npublic class PackagingPoint extends Artifact {\n    public static final String NONE = \"none\";\n    private List<Item> items = new LinkedList<>();\n\n    @OPERATION\n    public void init() {\n        // removeObsProperty(\"order\");\n    }\n\n    @OPERATION\n    public void install() throws OperationException {\n        execLinkedOp(\"out-fp\", \"install\", getId(), new String[] {});\n    }\n\n    @OPERATION\n    public void setOrder(List<String> order) {\n        defineObsProperty(\"order\", order);\n        defineObsProperty(\"outstanding\", new ArrayList<String>(order));\n    }\n\n    @SuppressWarnings(\"unchecked\")\n    @OPERATION\n    public void deliver() throws Exception {\n        List<String> outstanding = (List<String>) getObsProperty(\"outstanding\").getValue();\n        if (outstanding.isEmpty()) {\n            System.out.println(\"Delivered: \" + items);\n        } else\n            throw new Exception(\"No item to deliver for: \" + getId().getName());\n    }\n\n    @SuppressWarnings(\"unchecked\")\n    @LINK\n    public void give(Item item) throws Exception {\n        List<String> outstanding = (List<String>) getObsProperty(\"outstanding\").getValue();\n        if (outstanding.contains(item.type())) {\n            items.add(item);\n            outstanding.remove(item.type());\n            updateObsProperty(\"outstanding\", outstanding);\n        } else \n            throw new Exception(\"Item: \" + item.type() + \"  not required by: \" + getId().getName());\n    }}", "/java/artifacts/Robot.java": "package artifacts;\n\nimport java.util.Arrays;\nimport java.util.List;\n\nimport cartago.ARTIFACT_INFO;\nimport cartago.Artifact;\nimport cartago.ArtifactId;\nimport cartago.OPERATION;\nimport cartago.OUTPORT;\nimport cartago.OpFeedbackParam;\nimport model.Item;\n\n\n@ARTIFACT_INFO(outports = { @OUTPORT(name=\"out-fp\")})\npublic class Robot extends Artifact {\n    private static final List<String> LOAD_TYPES = Arrays.asList(new String[] {\"artifacts.AccessPoint\", \"artifacts.StoragePoint\", \"artifacts.Workstation\"});\n    private static final List<String> UNLOAD_TYPES = Arrays.asList(new String[] {\"artifacts.PackagingPoint\", \"artifacts.StoragePoint\", \"artifacts.Workstation\"});\n    private static final String AT = \"at\";\n    private static final String ENERGY = \"energy\";\n    private static final String MAX_ENERGY = \"maxEnergy\";\n    private static final String HOLDING = \"holding\";\n    private static final String NONE = \"none\";\n    private static final String STATE = \"state\";\n    private static final String IDLE = \"idle\";\n    private static final String MOVING = \"moving\";\n    private static final String LOADING = \"loading\";\n    private static final String UNLOADING = \"unloading\";\n    private static final String CHARGING = \"charging\";\n\n    private static final int MOVE_COST = 100;\n    private static final int LOAD_COST = 50;\n    private static final int RECHARGE_AMOUNT = 300;\n\n    private Item item;\n    \n    @OPERATION\n    public void init(String location, int maxEnergy) {\n        defineObsProperty(STATE, IDLE);\n        defineObsProperty(HOLDING, NONE);\n        defineObsProperty(AT, location);\n        defineObsProperty(ENERGY, maxEnergy);\n        defineObsProperty(MAX_ENERGY, maxEnergy);\n    }\n\n    @OPERATION\n    public void move(String location) throws Exception {\n        int energy = getObsProperty(ENERGY).intValue();\n        if (energy < MOVE_COST) throw new Exception(\"Insufficient Energy to move: \" + getId().getName());\n\n        String at = getObsProperty(AT).stringValue();\n        updateObsProperty(STATE, MOVING);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", MOVING);\n\n        Thread.sleep(2000);\n        execLinkedOp(\"out-fp\", \"move\", getId().getName(), at, location);\n\n        updateObsProperty(STATE, IDLE);\n        updateObsProperty(AT, location);\n        updateObsProperty(ENERGY, energy - MOVE_COST);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", IDLE);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"at\", location);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"energy\", getObsProperty(ENERGY).stringValue());\n    }\n\n    @OPERATION\n    public void charge() throws Exception {\n        cartago.ArtifactId deviceId = getDeviceArtifactId(getObsProperty(AT).stringValue());\n        if (deviceId.getArtifactType().equals(\"artifacts.RobotChargePoint\")) {\n            execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", CHARGING);\n            Thread.sleep(1000);\n            updateObsProperty(ENERGY, getObsProperty(ENERGY).intValue() + RECHARGE_AMOUNT);\n            execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", IDLE);\n            execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"energy\", getObsProperty(ENERGY).stringValue());\n        }\n    }\n\n\n    private ArtifactId getDeviceArtifactId(String at) throws Exception {\n        OpFeedbackParam<ArtifactId> deviceId = new OpFeedbackParam<>();\n        \n        // Getting device at location...\n        execLinkedOp(\"out-fp\", \"location\", at, deviceId);\n\n        // Checking Device Type (should be artifacts.AccessPoint)\n        return deviceId.get();\n    }\n\n    @OPERATION\n    public void load() throws Exception {\n        int energy = getObsProperty(ENERGY).intValue();\n        if (energy < MOVE_COST) throw new Exception(\"Insufficient Energy to load: \" + getId().getName());\n\n        String at = getObsProperty(AT).stringValue();\n        ArtifactId did = getDeviceArtifactId(at);\n        if (!LOAD_TYPES.contains(did.getArtifactType())) {\n            throw new Exception(\"Invalid Location:  \" + at + \" device: \" + did.getArtifactType());\n        }\n\n        // Executing Operation on device (hopefully)\n        updateObsProperty(STATE, LOADING);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", LOADING);\n\n        Thread.sleep(2000);\n        OpFeedbackParam<Item> item = new OpFeedbackParam<>();\n        execLinkedOp(did, \"take\", item);\n        this.item = item.get();\n\n        updateObsProperty(HOLDING, this.item.type());\n        updateObsProperty(ENERGY, energy - LOAD_COST);\n        updateObsProperty(STATE, IDLE);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", IDLE);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"holding\", this.item.type());\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"energy\", getObsProperty(ENERGY).stringValue());\n    }\n\n    @OPERATION\n    public void unload() throws Exception {\n        int energy = getObsProperty(ENERGY).intValue();\n        if (energy < MOVE_COST) throw new Exception(\"Insufficient Energy to unload: \" + getId().getName());\n\n        String at = getObsProperty(AT).stringValue();\n        ArtifactId did = getDeviceArtifactId(at);\n        if (!UNLOAD_TYPES.contains(did.getArtifactType())) {\n            throw new Exception(\"Invalid Location:  \" + at + \" device: \" + did.getArtifactType());\n        }\n\n        // Executing Operation on device (hopefully)\n        updateObsProperty(STATE, UNLOADING);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", UNLOADING);\n\n        Thread.sleep(2000);\n        execLinkedOp(did, \"give\", item);\n        updateObsProperty(HOLDING, NONE);\n        updateObsProperty(ENERGY, energy - LOAD_COST);\n        updateObsProperty(STATE, IDLE);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"status\", IDLE);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"holding\", NONE);\n        execLinkedOp(\"out-fp\", \"setRobotField\", getId().getName(), \"energy\", getObsProperty(ENERGY).stringValue());\n    }\n}", "/java/artifacts/RobotChargePoint.java": "package artifacts;\n\nimport cartago.ARTIFACT_INFO;\nimport cartago.Artifact;\nimport cartago.ArtifactConfig;\nimport cartago.OPERATION;\nimport cartago.OUTPORT;\nimport cartago.OperationException;\n\n@ARTIFACT_INFO(outports = { @OUTPORT(name=\"out-fp\") })\npublic class RobotChargePoint extends Artifact {\n    public static final String NONE = \"none\";\n    private int maxEnergy;\n\n    @OPERATION\n    public void init(int maxEnergy) {\n        this.maxEnergy = maxEnergy;\n        defineObsProperty(\"available\", NONE);\n    }\n\n    @OPERATION\n    public void install(String name) throws OperationException{\n        execLinkedOp(\"out-fp\", \"install\", getId(), new String[] {});\n        \n        try {\n            makeArtifact(name, \"artifacts.Robot\", new ArtifactConfig(getId().getName(), maxEnergy));\n            execLinkedOp(\"out-fp\", \"place\", name, getId().getName());\n        } catch (OperationException e) {\n            e.printStackTrace();\n        }\n    }\n}", "/java/artifacts/StoragePoint.java": "package artifacts;\n\nimport cartago.ARTIFACT_INFO;\nimport cartago.Artifact;\nimport cartago.LINK;\nimport cartago.OPERATION;\nimport cartago.OUTPORT;\nimport cartago.OpFeedbackParam;\nimport cartago.OperationException;\nimport model.Item;\n\n@ARTIFACT_INFO(outports = { @OUTPORT(name=\"out-fp\") })\npublic class StoragePoint extends Artifact {\n    public static final String NONE = \"none\";\n    private Item item;\n\n    @OPERATION\n    public void init() {\n        defineObsProperty(\"available\", NONE);\n    }\n\n    @OPERATION\n    public void install() throws OperationException {\n        execLinkedOp(\"out-fp\", \"install\", getId(), new String[] { \"available\" });\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"available\", NONE);\n    }\n\n    @LINK\n    public void take(OpFeedbackParam<Item> item) throws Exception {\n        if (this.item == null) throw new Exception(\"Storage Point \" + getId().getName() + \": NO ITEM AVAILABLE\");\n\n        updateObsProperty(\"available\", NONE);\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"available\", NONE);\n        item.set(this.item);\n        this.item = null;\n    }\n\n    @LINK\n    public void give(Item item) throws Exception {\n        if (this.item != null) throw new Exception(\"Storage Point \" + getId().getName() + \" is FULL: \" + this.item.type());\n        updateObsProperty(\"available\", item.type());\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"available\", item.type());\n        this.item = item;\n    }\n}", "/java/artifacts/Warehouse.java": "package artifacts;\n\nimport cartago.Artifact;\nimport cartago.OPERATION;\nimport cartago.ObsProperty;\nimport cartago.OpFeedbackParam;\nimport model.Item;\n\npublic class Warehouse extends Artifact {\n    @OPERATION\n    public void init() {\n    }\n\n    @OPERATION\n    public void add(String item, int qty) {\n        ObsProperty property = getObsProperty(item);\n        if (property == null)\n            defineObsProperty(item, qty);\n        else\n            updateObsProperty(item, property.intValue()+qty);    \n    }\n\n    @OPERATION\n    public void retrieve(String type, OpFeedbackParam<Item> item) throws Exception {\n        int qty = getObsProperty(type).intValue();\n        if (qty == 0)\n            throw new Exception(\"Warehouse contains no items of type: \" + type);\n        updateObsProperty(type, qty-1);\n        item.set(new Item(type));\n    }\n    \n}", "/java/artifacts/Workstation.java": "package artifacts;\n\nimport java.util.ArrayList;\nimport java.util.List;\n\nimport cartago.ARTIFACT_INFO;\nimport cartago.Artifact;\nimport cartago.LINK;\nimport cartago.OPERATION;\nimport cartago.OUTPORT;\nimport cartago.OpFeedbackParam;\nimport cartago.OperationException;\nimport model.Item;\n\n@ARTIFACT_INFO(outports = { @OUTPORT(name=\"out-fp\") })\npublic class Workstation extends Artifact {\n    private static final String IDLE = \"idle\";\n    private static final String READY = \"ready\";\n    private static final String ACTIVE = \"active\";\n    private static final String DONE = \"done\";\n    private static final String INPUTS_NEEDED = \"inputsNeeded\";\n    private static final String INPUTS = \"inputs\";\n    private static final String STATE = \"state\";\n\n    private Item[] inputs;\n    private Item output;\n\n    @OPERATION\n    public void init() {\n        defineObsProperty(STATE, IDLE);\n    }\n\n    @OPERATION\n    public void configure(List<String> inputTypes, String outputType, long duration) throws Exception {\n        defineObsProperty(\"inputs\", inputTypes);\n        defineObsProperty(\"output\", outputType);\n\n        inputs = new Item[inputTypes.size()];\n\n        defineObsProperty(INPUTS_NEEDED, new ArrayList<String>(inputTypes));\n        defineObsProperty(\"duration\", duration);\n\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"inputs\", getObsProperty(\"inputs\").getValue().toString());\n        //execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"outputs\", getObsProperty(\"outputs\").getValue().toString());\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"outputs\", getObsProperty(\"output\").getValue().toString());\n        execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"inputsNeeded\", getObsProperty(\"inputs\").getValue().toString());\n    }\n\n    @OPERATION\n    public void install() throws OperationException {\n        execLinkedOp(\"out-fp\", \"install\", getId(), new String[] {\"inputs\", \"inputsNeeded\", \"outputs\", \"available\"});\n    }\n    \n    @OPERATION\n    public void operate() throws Exception {\n        if (!getObsProperty(STATE).stringValue().equals(READY)) {\n            throw new Exception(\"Workstation: \" + getId().getName() + \" is not ready for operation\");\n        }\n\n        updateObsProperty(STATE, ACTIVE);\n        execLinkedOp(\"out-fp\", \"setStatus\", getId().getName(), ACTIVE);\n\n        Thread.sleep(getObsProperty(\"duration\").longValue());\n        \n        inputs = new Item[inputs.length];\n        output = new Item(getObsProperty(\"output\").stringValue());\n        updateObsProperty(STATE, DONE);\n        execLinkedOp(\"out-fp\", \"setStatus\", getId().getName(), DONE);\n    }\n    \n    @SuppressWarnings(\"unchecked\")\n    private List<String> createInputsNeededList() {\n        List<String> inputs = (List<String>) getObsProperty(INPUTS).getValue();\n        return new ArrayList<String>(inputs);\n    }\n\n    @SuppressWarnings(\"unchecked\")\n    @LINK\n    public void give(Item item) throws Exception {\n        int i = 0;\n        List<String> types = (List<String>) getObsProperty(INPUTS).getValue();\n        List<String> inputsNeeded = (List<String>) getObsProperty(INPUTS_NEEDED).getValue();\n        while (i < inputs.length) {\n            if (types.get(i).equals(item.type()) && inputs[i] == null) {\n                inputs[i] = item;\n\n                // Update the inputs needed list to reflect the addition of the new item...\n                inputsNeeded.remove(item.type());\n                updateObsProperty(INPUTS_NEEDED, inputsNeeded);\n                execLinkedOp(\"out-fp\", \"setCustomField\", getId().getName(), \"inputsNeeded\", inputsNeeded.toString());\n                if (inputsNeeded.isEmpty()) {\n                    updateObsProperty(STATE, READY);\n                    execLinkedOp(\"out-fp\", \"setStatus\", getId().getName(), READY);\n                }\n                return;\n            }\n            i++;\n        }\n        throw new Exception(\"Item not required: \" + item.type());\n    }\n\n    @LINK\n    public void take(OpFeedbackParam<Item> item) throws Exception {\n        if (this.output == null) throw new Exception(\"Workstation \" + getId().getName() + \": NO ITEM AVAILABLE\");\n\n        item.set(this.output);\n        this.output = null;\n        updateObsProperty(INPUTS_NEEDED, createInputsNeededList());\n        updateObsProperty(STATE, IDLE);\n        execLinkedOp(\"out-fp\", \"setStatus\", getId().getName(), IDLE);\n    }\n\n}", "/java/model/Item.java": "package model;\n\npublic class Item {\n    private String type;\n\n    public Item(String type) {\n        this.type = type;\n    }\n\n    public String type() {\n        return type;\n    }\n    \n}\n", "/java/model/Location.java": "package model;\n\nimport cartago.ArtifactId;\n\npublic class Location {\n    private ArtifactId id;\n    private String occupancy;\n\n    public Location(ArtifactId id) {\n        this.id = id;\n    }\n\n    public ArtifactId id() {\n        return id;\n    }\n\n    public String occupancy() {\n        return occupancy;\n    }\n\n    public void occupancy(String occupancy) {\n        this.occupancy = occupancy;\n    }\n\n    public boolean isOccupied() {\n        return occupancy != null;\n    }\n}\n", "/java/modules/PropertyExtractor.java": "package modules;\n\nimport java.util.Collection;\n\nimport astra.core.Module;\nimport astra.formula.Formula;\nimport astra.formula.Predicate;\nimport astra.term.ListTerm;\nimport astra.term.Primitive;\nimport cartago.ArtifactObsProperty;\n\npublic class PropertyExtractor extends Module {\n    @SuppressWarnings(\"unchecked\")\n    @TERM\n    public ListTerm listValues(ArtifactObsProperty property) {\n        ListTerm list = new ListTerm();\n        for (String value : (Collection<String>) property.getValue()) {\n            list.add(Primitive.newPrimitive(value));\n        };\n\n        return list;\n    }\n\n    @TERM\n    public String stringValue(ArtifactObsProperty property) {\n        return property.stringValue();\n    }\n    \n    //step 2. needed for comparison\n    @TERM\n    public int intValue(ArtifactObsProperty property) {\n        return property.intValue();\n    }\n\n    //step 7. current time in ms for order timing\n    @TERM\n    public long currentTimeMillis() {\n        return System.currentTimeMillis();\n    }\n\n    @FORMULA\n    public Formula isBound(String value) {\n        return value == null ? Predicate.FALSE:Predicate.TRUE;\n    }\n}\n", "/java/ui/PlantViewer.java": "package ui;\n\nimport java.awt.BorderLayout;\nimport java.awt.GridLayout;\n\nimport javax.swing.BoxLayout;\nimport javax.swing.JFrame;\nimport javax.swing.JLabel;\nimport javax.swing.JPanel;\n\npublic class PlantViewer extends JFrame {\n    private JPanel floorplan;\n    private JPanel robots;\n\n    public PlantViewer() {\n        this.setLayout(new BorderLayout());\n        this.setTitle(\"Simple Plant Viewer\");\n        JPanel columns = new JPanel(new GridLayout(1, 2));\n        add(columns, BorderLayout.CENTER);\n        JPanel colPanel = new JPanel(new BorderLayout());\n        colPanel.add(new JLabel(\"Zones\"), BorderLayout.NORTH);\n        colPanel.add(floorplan = new JPanel(), BorderLayout.CENTER);\n        columns.add(colPanel);\n        floorplan.setLayout(new BoxLayout(floorplan, BoxLayout.PAGE_AXIS));\n\n        JPanel robPanel = new JPanel(new BorderLayout());\n        robPanel.add(new JLabel(\"Robots\"), BorderLayout.NORTH);\n        robPanel.add(robots = new JPanel(), BorderLayout.CENTER);\n        columns.add(robPanel);\n        // columns.add(robots = new JPanel());\n        // robots.setLayout(new BoxLayout(robots, BoxLayout.PAGE_AXIS));\n        robots.setLayout(new GridLayout(1, 1));\n        // robots.add(new JLabel(\"Robots\"));\n        setSize(400, 800);\n        setVisible(true);\n    }\n\n    public ZonePanel addZone(String name, String type) {\n        ZonePanel zPanel = new ZonePanel(this, name, type);\n        floorplan.add(zPanel);\n        // invalidate();\n        return zPanel;\n    }\n    \n    public RobotPanel addRobot(String name) {\n        RobotPanel zPanel = new RobotPanel(this, name);\n        robots.add(zPanel);\n        robots.setLayout(new GridLayout(robots.getComponentCount(), 1));\n        // invalidate();\n        return zPanel;\n    }\n    \n}\n", "/java/ui/RobotPanel.java": "package ui;\n\nimport java.awt.BorderLayout;\nimport java.awt.Dimension;\nimport java.awt.GridLayout;\nimport java.util.HashMap;\nimport java.util.Map;\n\nimport javax.swing.JLabel;\nimport javax.swing.JPanel;\nimport javax.swing.JTextField;\n\npublic class RobotPanel extends JPanel {\n    private Map<String, JTextField> fields = new HashMap<>();\n    private PlantViewer viewer;\n    private JPanel heading;\n    private JPanel base;\n\n    public RobotPanel(PlantViewer viewer, String name) {\n        this.viewer = viewer;\n        this.setPreferredSize(new Dimension(200, 90));\n\n        setLayout(new BorderLayout());\n\n        heading = new JPanel();\n        heading.add(new JLabel(\"Robot: \" + name));\n        add(heading, BorderLayout.NORTH);\n\n        base = new JPanel();\n        addField(\"at\",\"Location:\", \"none\");\n        addField(\"status\",\"Status:\", \"idle\");\n        addField(\"holding\",\"Holding:\", \"none\");\n        addField(\"energy\",\"Energy Level:\", \"\");\n        base.setLayout(new GridLayout(base.getComponentCount()/2, 2));\n        add(base, BorderLayout.CENTER);\n\n        this.viewer.revalidate();\n    }\n\n    public void addField(String key, String name, String value) {\n        JTextField textField = new JTextField(value);\n        base.add(new JLabel(name));\n        base.add(textField);\n        fields.put(key, textField);\n\n    }\n\n    public void setField(String key, String value) {\n        fields.get(key).setText(value);\n    }\n}\n", "/java/ui/ZonePanel.java": "package ui;\n\nimport java.awt.Dimension;\nimport java.awt.GridLayout;\nimport java.util.HashMap;\nimport java.util.Map;\n\nimport javax.swing.JLabel;\nimport javax.swing.JPanel;\nimport javax.swing.JTextField;\nimport java.awt.BorderLayout;\n\npublic class ZonePanel extends JPanel {\n    private JTextField available = new JTextField(\"empty\", 20);\n    private JTextField status = new JTextField(\"idle\", 20);\n    private PlantViewer viewer;\n    private JPanel heading;\n    private JPanel base;\n\n    public ZonePanel(PlantViewer viewer, String name, String type) {\n        this.viewer = viewer;\n        this.setPreferredSize(new Dimension(200, 90));\n\n        setLayout(new BorderLayout());\n\n        heading = new JPanel();\n        heading.add(new JLabel(name + \" [\"+type+\"]\"));\n        add(heading, BorderLayout.NORTH);\n\n        base = new JPanel();\n        base.setLayout(new GridLayout(2, 2));\n        base.add(new JLabel(\"Occupied:\"));\n        base.add(available);\n        base.add(new JLabel(\"Status:\"));\n        base.add(status);\n        add(base, BorderLayout.CENTER);\n\n        this.viewer.revalidate();\n    }\n\n    public void setAvailable(String item) {\n        available.setText(item);\n    }\n    \n    public void setStatus(String status) {\n        this.status.setText(status);\n    }\n\n    private Map<String, JTextField> customFields = new HashMap<>();\n    \n    public void addCustomField(String name, String initial) {\n        JTextField custom = new JTextField(initial, 20);\n        customFields.put(name, custom);\n        base.add(new JLabel(name));\n        base.add(custom);\n        base.setLayout(new GridLayout(2+customFields.size(), 1));\n        \n        this.setPreferredSize(new Dimension(200, 30*(3+customFields.size())));\n    }\n\n    public void setCustomField(String custom, String value) {\n        customFields.get(custom).setText(value);\n    }\n    \n}\n"}, "currentPath": "/astra/Main.astra", "emptyFolders": []})); location.reload();